class Solution {
public:
    string originalDigits(string s) {
        int count[26] = {0};
        for (char c : s) count[c - 'a']++;

        int digits[10] = {0};
        digits[0] = count['z' - 'a'] + count['w' - 'a'] + count['u' - 'a'];
        digits[2] = count['x' - 'a'] + count['v' - 'a'] + count['u' - 'a'];
        digits[4] = count['f' - 'a'] + count['u' - 'a'] + count['r' - 'a'];
        digits[6] = count['s' - 'a'] + count['x' - 'a'];
        digits[8] = count['e' - 'a'] + count['i' - 'a'] + count['g' - 'a'] + count['h' - 'a'] + count['t' - 'a'];

        digits[1] = count['o' - 'a'] - digits[0] - digits[2] - digits[4];
        digits[3] = count['h' - 'a'] - digits[8];
        digits[5] = count['v' - 'a'] - digits[2];
        digits[7] = count['n' - 'a'] - digits[6];
        digits[9] = count['i' - 'a'] - digits[8];

        string result = "";
        for (int i = 0; i < 10; i++) {
            for (int j = 0; j < digits[i]; j++) result += '0' + i;
        }
        return result;
    }
};
```

